"use strict";(self.webpackChunkheiman_wiki_public=self.webpackChunkheiman_wiki_public||[]).push([["8644"],{3625(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/heiman-wiki-public/fr/blog/welcome","source":"@site/i18n/fr/docusaurus-plugin-content-blog/2021-08-26-welcome/index.mdx","title":"Welcome to Heiman Technology Wiki","description":"Bienvenue sur le Wiki Heiman Technology ! Ce site sert de centre de documentation complet pour les produits et solutions de Heiman Technology.","date":"2021-08-26T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/fr/blog/tags/heiman","description":"Actualit\xe9s et mises \xe0 jour de Heiman Technology"}],"readingTime":0.61,"hasTruncateMarker":false,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/fr/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"welcome","title":"Welcome to Heiman Technology Wiki","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"nextItem":{"title":"Heiman Matter Smart Smoke Alarm Officially Launched","permalink":"/heiman-wiki-public/fr/blog/mdx-blog-post"}},"content":"Bienvenue sur le Wiki Heiman Technology ! Ce site sert de centre de documentation complet pour les produits et solutions de Heiman Technology.\\n\\n## Ce que Vous Trouverez Ici\\n\\n- **Documentation Produit** \u2014 Sp\xe9cifications techniques d\xe9taill\xe9es, guides d\'installation et manuels d\'utilisation\\n- **Ressources D\xe9veloppeur** \u2014 Guides d\'int\xe9gration d\'API, protocoles de communication et tutoriels de connexion \xe0 des plateformes tierces\\n- **Actualit\xe9s et Mises \xe0 Jour** \u2014 Derni\xe8res nouvelles de l\'entreprise, lancements de produits et tendances de l\'industrie\\n- **FAQ et D\xe9pannage** \u2014 Questions courantes et solutions pour vous aider \xe0 tirer le meilleur parti de vos produits Heiman\\n\\n## Rester Connect\xe9\\n\\nSuivez-nous sur les r\xe9seaux sociaux pour les derni\xe8res mises \xe0 jour :\\n\\n- **X (Twitter)** : [@heimantech](https://x.com/heimantech)\\n- **LinkedIn** : [Heiman Technology](https://linkedin.com/company/heimantech)\\n- **Site Web** : [https://www.heiman.com.cn](https://www.heiman.com.cn)"},{"id":"mdx-blog-post","metadata":{"permalink":"/heiman-wiki-public/fr/blog/mdx-blog-post","source":"@site/i18n/fr/docusaurus-plugin-content-blog/2021-08-01-mdx-blog-post.mdx","title":"Heiman Matter Smart Smoke Alarm Officially Launched","description":"Heiman Technology est fi\xe8re d\'annoncer le lancement officiel de notre d\xe9tecteur de fum\xe9e intelligent compatible Matter, une \xe9tape importante dans notre mission de fournir des solutions de s\xe9curit\xe9 domestique intelligente et interop\xe9rable.","date":"2021-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Matter","permalink":"/heiman-wiki-public/fr/blog/tags/matter","description":"Protocole Matter"},{"inline":false,"label":"S\xe9curit\xe9 Incendie Intelligente","permalink":"/heiman-wiki-public/fr/blog/tags/smart-fire","description":"Produits et solutions de s\xe9curit\xe9 incendie intelligente"}],"readingTime":1.04,"hasTruncateMarker":false,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/fr/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"mdx-blog-post","title":"Heiman Matter Smart Smoke Alarm Officially Launched","authors":["heiman"],"tags":["matter","smart-fire"]},"unlisted":false,"prevItem":{"title":"Welcome to Heiman Technology Wiki","permalink":"/heiman-wiki-public/fr/blog/welcome"},"nextItem":{"title":"Heiman Technology Milestones","permalink":"/heiman-wiki-public/fr/blog/long-blog-post"}},"content":"Heiman Technology est fi\xe8re d\'annoncer le lancement officiel de notre d\xe9tecteur de fum\xe9e intelligent compatible Matter, une \xe9tape importante dans notre mission de fournir des solutions de s\xe9curit\xe9 domestique intelligente et interop\xe9rable.\\n\\n## Pourquoi Matter ?\\n\\nMatter est le nouveau standard de l\'industrie pour la connectivit\xe9 des maisons intelligentes, permettant aux appareils de diff\xe9rents fabricants de fonctionner ensemble de mani\xe8re transparente. En adoptant Matter, Heiman garantit que nos d\xe9tecteurs de fum\xe9e peuvent s\'int\xe9grer facilement dans n\'importe quel \xe9cosyst\xe8me de maison intelligente.\\n\\n```jsx title=\\"src/components/SmokeAlarm.jsx\\"\\nfunction SmokeAlarm({ status }) {\\n  return (\\n    <div className=\\"alarm-card\\">\\n      <h3>D\xe9tecteur de Fum\xe9e Intelligent Heiman</h3>\\n      <p>Statut : {status === \'normal\' ? \'Fonctionnement Normal\' : \'Alerte\'}</p>\\n    </div>\\n  );\\n}\\n```\\n\\n:::note\\n\\nLe d\xe9tecteur de fum\xe9e intelligent Matter de Heiman est compatible avec Alexa, Google Home et Apple HomeKit, permettant une exp\xe9rience de maison intelligente v\xe9ritablement int\xe9gr\xe9e.\\n\\n:::\\n\\n## Principales Caract\xe9ristiques\\n\\n- **Certification Matter** \u2014 Interop\xe9rabilit\xe9 transparente avec les principales plateformes de maison intelligente\\n- **Connectivit\xe9 Cellulaire** \u2014 Sauvegarde 4G/NB-IoT pour une fiabilit\xe9 accrue\\n- **D\xe9tection Intelligente** \u2014 Algorithme anti-fausses alarmes r\xe9duisant les notifications intempestives\\n- **Multi-notification** \u2014 Alertes push sur smartphone, sir\xe8ne et notification aux contacts d\'urgence\\n\\n## Disponibilit\xe9\\n\\nLe d\xe9tecteur de fum\xe9e intelligent Matter de Heiman est maintenant disponible \xe0 la commande. Veuillez contacter notre \xe9quipe commerciale pour les prix et la disponibilit\xe9 dans votre r\xe9gion."},{"id":"long-blog-post","metadata":{"permalink":"/heiman-wiki-public/fr/blog/long-blog-post","source":"@site/i18n/fr/docusaurus-plugin-content-blog/2019-05-29-long-blog-post.mdx","title":"Heiman Technology Milestones","description":"2005","date":"2019-05-29T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/fr/blog/tags/heiman","description":"Actualit\xe9s et mises \xe0 jour de Heiman Technology"}],"readingTime":0.93,"hasTruncateMarker":false,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/fr/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"long-blog-post","title":"Heiman Technology Milestones","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Heiman Matter Smart Smoke Alarm Officially Launched","permalink":"/heiman-wiki-public/fr/blog/mdx-blog-post"},"nextItem":{"title":"Heinan Technology Recognized as National \\"Little Giant\\" Enterprise","permalink":"/heiman-wiki-public/fr/blog/first-blog-post"}},"content":"## 2005\\n\\nHeiman Technology a \xe9t\xe9 fond\xe9e \xe0 Shenzhen, en Chine, se concentrant initialement sur la R&D et la production de produits de s\xe9curit\xe9 \xe9lectronique.\\n\\n## 2008\\n\\nLanc\xe9 le premier d\xe9tecteur de fum\xe9e sans fil, marquant notre entr\xe9e sur le march\xe9 de la s\xe9curit\xe9 intelligente.\\n\\n## 2012\\n\\nD\xe9veloppement r\xe9ussi des premiers produits de communication cellulaire, permettant la surveillance \xe0 distance et l\'alarme.\\n\\n## 2015\\n\\nReconnue comme Entreprise Nationale de Haute Technologie, validant davantage notre force en mati\xe8re de R&D technologique.\\n\\n## 2018\\n\\n\xc9tablissement d\'une base de fabrication au Vietnam, \xe9largissant notre capacit\xe9 de production mondiale et notre empreinte logistique.\\n\\n## 2020\\n\\nLanc\xe9 une nouvelle g\xe9n\xe9ration de produits prenant en charge les protocoles IoT (NB-IoT, Cat.M, etc.), connectant de mani\xe8re transparente avec les principales plateformes cloud.\\n\\n## 2022\\n\\nReconnue comme Entreprise Nationale Sp\xe9cialis\xe9e et Nouvelle \xab Petit G\xe9ant \xbb, obtenant l\'accr\xe9ditation CNAS pour notre laboratoire d\'essais.\\n\\n## 2023\\n\\nLanc\xe9 le premier produit prenant en charge le protocole Matter, leader de l\'industrie en mati\xe8re de compatibilit\xe9 inter-plateformes.\\n\\n## 2024\\n\\nPlus de 1000 certifications et brevets de produits, produits export\xe9s dans plus de 100 pays et r\xe9gions, capacit\xe9 de production annuelle d\xe9passant 15 millions d\'unit\xe9s."},{"id":"first-blog-post","metadata":{"permalink":"/heiman-wiki-public/fr/blog/first-blog-post","source":"@site/i18n/fr/docusaurus-plugin-content-blog/2019-05-28-first-blog-post.mdx","title":"Heinan Technology Recognized as National \\"Little Giant\\" Enterprise","description":"Heiman Technology a \xe9t\xe9 officiellement reconnue comme Entreprise Nationale Sp\xe9cialis\xe9e et Nouvelle \xab Petit G\xe9ant \xbb. Cette reconnaissance prestigieuse met en \xe9vidence notre force en mati\xe8re d\'innovation technologique et notre position de leader dans l\'industrie de la s\xe9curit\xe9 intelligente.","date":"2019-05-28T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/fr/blog/tags/heiman","description":"Actualit\xe9s et mises \xe0 jour de Heiman Technology"}],"readingTime":0.72,"hasTruncateMarker":false,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/fr/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"first-blog-post","title":"Heinan Technology Recognized as National \\"Little Giant\\" Enterprise","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Heiman Technology Milestones","permalink":"/heiman-wiki-public/fr/blog/long-blog-post"}},"content":"Heiman Technology a \xe9t\xe9 officiellement reconnue comme Entreprise Nationale Sp\xe9cialis\xe9e et Nouvelle \xab Petit G\xe9ant \xbb. Cette reconnaissance prestigieuse met en \xe9vidence notre force en mati\xe8re d\'innovation technologique et notre position de leader dans l\'industrie de la s\xe9curit\xe9 intelligente.\\n\\n## Qu\'est-ce que le Programme \xab Petit G\xe9ant \xbb ?\\n\\nLe programme national \xab Petit G\xe9ant \xbb est con\xe7u pour identifier et soutenir les PME sp\xe9cialis\xe9es et innovantes qui poss\xe8dent des technologies de base, une forte capacit\xe9 d\'innovation et un grand potentiel de march\xe9. Ces entreprises sont consid\xe9r\xe9es comme les piliers de la fabrication de pointe et de l\'innovation technologique de la Chine.\\n\\n## Notre Parcours\\n\\nDepuis notre fondation en 2005, Heiman Technology s\'est toujours engag\xe9e dans la R&D et l\'innovation de produits de capteurs intelligents. Cette reconnaissance est un t\xe9moignage de nos efforts continus et de notre d\xe9vouement \xe0 fournir des produits de s\xe9curit\xe9 de haute qualit\xe9 \xe0 travers le monde."}]}}')}}]);